          break;
        }
      }
    } catch {}

    // Navigate to Sign Up
    const selectors = config.selectors || {};
    if (selectors.signUpLink) {
      await safeClick(page, selectors.signUpLink, { timeout: defaultTimeout, text: 'Sign Up' }).catch(() => {});
    } else {
